    useEffect(() => { props.handleError('') }, []);

    useEffect(() => {
        API.getImages()
            .then((x) => {
                setImages(x);
                setIsLoading(false);
            })
            .catch((err) => props.handleError(err)); // handleError defined in App.jsx
