First, add a `useDebouncedEffect` custom hook to handle the debounced updates inside the `MyBlock` component:

```javascript
import { useEffect, useRef } from 'react';

function useDebouncedEffect(effect, deps, delay) {
  const callback = useRef();

  useEffect(() => {
    callback.current = effect;
  }, [effect]);

  useEffect(() => {
    const handler = setTimeout(() => {
      callback.current();
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [...deps, delay]);
}
```

